import {
  Badge as BadgeBase,
  BadgeWithDot,
  BadgeWithIcon,
  type BadgeColor,
} from '@/vendor/untitled-ui/base/badges/badges';
import type {
  BadgeColors,
  BadgeTypes,
  IconComponentType,
} from '@/vendor/untitled-ui/base/badges/badge-types';

export interface BadgeProps<
  T extends BadgeTypes = 'pill-color',
> extends React.HTMLAttributes<HTMLSpanElement> {
  type?: T;
  size?: 'sm';
  color?: BadgeColors;
  children?: React.ReactNode;
  variant?: 'default' | 'dot' | 'icon';
  iconLeading?: IconComponentType;
  iconTrailing?: IconComponentType;
}

export function Badge<T extends BadgeTypes = 'pill-color'>(
  props: BadgeProps<T>,
) {
  const {
    color = 'gray',
    type = 'pill-color' as T,
    variant = 'default',
    ...rest
  } = props;

  const badgeColor = color as BadgeColor<T>;

  if (variant === 'dot') {
    return (
      <BadgeWithDot
        type={type}
        color={badgeColor}
        {...rest}
      >
        {props.children}
      </BadgeWithDot>
    );
  }

  if (variant === 'icon') {
    return (
      <BadgeWithIcon
        type={type}
        color={badgeColor}
        {...rest}
      >
        {props.children}
      </BadgeWithIcon>
    );
  }

  return (
    <BadgeBase
      type={type}
      color={badgeColor}
      {...rest}
    >
      {props.children}
    </BadgeBase>
  );
}
